section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/go-backend",
  "type": "object",
  "required": ["modulePath", "entry", "internalDirs"],
  "properties": {
    "modulePath": {"type": "string", "pattern": "^[a-z0-9./_-]+$"},
    "entry": {"const": "cmd/api/main.go"},
    "internalDirs": {
      "type": "array",
      "items": {"enum": ["handler", "service", "repository", "model", "middleware", "config"]},
      "minItems": 5,
      "uniqueItems": true
    },
    "externalInternalImports": {
      "type": "array",
      "description": "Must be empty: no file outside the module may import the module's internal/ packages.",
      "maxItems": 0
    },
    "forbiddenPatterns": {
      "type": "array",
      "items": {"enum": [
        "c.JSON(http.Status",
        "go func() { ... c.Request",
        "BindJSON(",
        "interface { } in repository/"
      ]}
    }
  }
}

example.code:
// internal/handler/user.go — REJECTED
func (h *UserHandler) Create(c *gin.Context) {
    var u model.User                          // direct domain bind (r3 violated)
    if err := c.BindJSON(&u); err != nil {     // BindJSON aborts (r7 violated)
        c.JSON(400, gin.H{"error": err})       // direct JSON (r8 violated)
        return
    }
    go func() { h.s.Process(c) }()             // c captured in goroutine (r5 violated)
}
